contracts/SAFEStaking.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import "@openzeppelin/contracts/token/ERC20/IERC20.sol";
import "@openzeppelin/contracts/token/ERC20/utils/SafeERC20.sol";
import "@openzeppelin/contracts/access/Ownable.sol";
import "@openzeppelin/contracts/utils/ReentrancyGuard.sol";

/**
 * @title SAFEStaking
 * @dev Staking contract for $SAFE tokens with REAL YIELD in USDC.
 *
 * FIX for Test 2: "Quelqu'un a-t-il une raison de GARDER le token ?"
 *
 * Key change vs v1: Rewards are paid in USDC (real yield), NOT in $SAFE.
 * Revenue from platform subscriptions (EUR) is converted to USDC and
 * distributed to stakers proportionally.
 *
 * This means:
 * - Staking does NOT inflate $SAFE supply
 * - Yield is REAL (backed by business revenue)
 * - Users have a reason to hold: revenue share in stables
 *
 * Model: Similar to GMX (real yield in ETH/USDC from trading fees)
 *
 * Additional utility from staking (not available via EUR subscription):
 * - Vote power multiplier (governance weight)
 * - Revenue share (USDC distribution)
 * - Priority access to new evaluations
 * - Exclusive API tier (raw data access)
 */
contract SAFEStaking is Ownable, ReentrancyGuard {
    using SafeERC20 for IERC20;

    IERC20 public immutable safeToken;
    IERC20 public immutable rewardToken; // USDC for real yield

    // =========================================
    // STAKING STATE
    // =========================================

    struct StakeInfo {
        uint256 amount;
        uint256 stakedAt;
        uint256 rewardDebt; // For reward-per-share accounting
    }

    struct UnstakeRequest {
        uint256 amount;
        uint256 unlockTime;
    }

    mapping(address => StakeInfo[]) public userStakes;
    mapping(address => UnstakeRequest[]) public unstakeRequests;
    mapping(address => uint256) public totalStakedByUser;

    uint256 public totalStaked;
    uint256 public totalStakers;

    // =========================================
    // REAL YIELD DISTRIBUTION (USDC)
    // =========================================

    // Accumulated reward per share (scaled by 1e18 for precision)
    uint256 public accRewardPerShare;
    // Total USDC distributed since inception
    uint256 public totalRewardsDistributed;
    // User's already-claimed rewards
    mapping(address => uint256) public userClaimedRewards;
    // User's pending reward debt (for accurate accounting on stake/unstake)
    mapping(address => uint256) public userRewardDebt;

    // =========================================
    // REVENUE TRACKING (transparency)
    // =========================================

    struct RevenueEpoch {
        uint256 usdcAmount;    // USDC deposited
        uint256 totalStaked;   // Total $SAFE staked at that time
        uint256 timestamp;
    }
    RevenueEpoch[] public revenueHistory;

    // =========================================
    // TIER SYSTEM
    // =========================================

    uint256 public constant BRONZE_THRESHOLD   = 100 * 10**18;
    uint256 public constant SILVER_THRESHOLD   = 500 * 10**18;
    uint256 public constant GOLD_THRESHOLD     = 1_000 * 10**18;
    uint256 public constant PLATINUM_THRESHOLD = 2_500 * 10**18;
    uint256 public constant DIAMOND_THRESHOLD  = 5_000 * 10**18;

    uint256 public constant UNSTAKE_COOLDOWN = 7 days;
    uint256 public constant MIN_STAKE = 100 * 10**18;

    // =========================================
    // EVENTS
    // =========================================

    event Staked(address indexed user, uint256 amount, uint256 totalUserStaked);
    event UnstakeRequested(address indexed user, uint256 amount, uint256 unlockTime);
    event Withdrawn(address indexed user, uint256 amount);
    event RewardsClaimed(address indexed user, uint256 usdcAmount);
    event RevenueDeposited(uint256 usdcAmount, uint256 totalStaked, uint256 rewardPerShare);
    event TierChanged(address indexed user, uint8 newTier);

    // =========================================
    // CONSTRUCTOR
    // =========================================

    constructor(
        address _safeToken,
        address _rewardToken  // USDC address on deployed chain
    ) Ownable(msg.sender) {
        require(_safeToken != address(0), "Invalid SAFE token");
        require(_rewardToken != address(0), "Invalid reward token");
        safeToken = IERC20(_safeToken);
        rewardToken = IERC20(_rewardToken);
    }

    // =========================================
    // REVENUE DEPOSIT (owner deposits USDC from platform revenue)
    // =========================================

    /**
     * @dev Deposit USDC revenue to distribute to stakers.
     * Called periodically (weekly/monthly) by the platform.
     *
     * Flow: EUR subscriptions → convert to USDC → deposit here → auto-distribute
     *
     * This is REAL YIELD: actual business revenue, not inflationary token emission.
     */
    function depositRevenue(uint256 usdcAmount) external onlyOwner {
        require(usdcAmount > 0, "Zero amount");
        require(totalStaked > 0, "No stakers");

        // Transfer USDC from owner to this contract
        rewardToken.safeTransferFrom(msg.sender, address(this), usdcAmount);

        // Update accumulated reward per share
        accRewardPerShare += (usdcAmount * 1e18) / totalStaked;
        totalRewardsDistributed += usdcAmount;

        // Record for transparency
        revenueHistory.push(RevenueEpoch({
            usdcAmount: usdcAmount,
            totalStaked: totalStaked,
            timestamp: block.timestamp
        }));

        emit RevenueDeposited(usdcAmount, totalStaked, accRewardPerShare);
    }

    // =========================================
    // STAKING
    // =========================================

    function stake(uint256 amount) external nonReentrant {
        require(amount >= MIN_STAKE, "Below minimum stake");

        // Claim any pending rewards first
        _claimPendingRewards(msg.sender);

        safeToken.safeTransferFrom(msg.sender, address(this), amount);

        bool isNewStaker = totalStakedByUser[msg.sender] == 0;

        userStakes[msg.sender].push(StakeInfo({
            amount: amount,
            stakedAt: block.timestamp,
            rewardDebt: 0
        }));

        totalStakedByUser[msg.sender] += amount;
        totalStaked += amount;

        // Update reward debt for accurate accounting
        userRewardDebt[msg.sender] = (totalStakedByUser[msg.sender] * accRewardPerShare) / 1e18;

        if (isNewStaker) {
            totalStakers++;
        }

        uint8 tier = getTier(msg.sender);
        emit TierChanged(msg.sender, tier);
        emit Staked(msg.sender, amount, totalStakedByUser[msg.sender]);
    }

    function requestUnstake(uint256 stakeIndex) external nonReentrant {
        require(stakeIndex < userStakes[msg.sender].length, "Invalid stake index");

        // Claim pending rewards before unstaking
        _claimPendingRewards(msg.sender);

        StakeInfo storage stakeInfo = userStakes[msg.sender][stakeIndex];
        require(stakeInfo.amount > 0, "Nothing to unstake");

        uint256 amount = stakeInfo.amount;
        uint256 unlockTime = block.timestamp + UNSTAKE_COOLDOWN;

        unstakeRequests[msg.sender].push(UnstakeRequest({
            amount: amount,
            unlockTime: unlockTime
        }));

        stakeInfo.amount = 0;
        totalStakedByUser[msg.sender] -= amount;
        totalStaked -= amount;

        // Update reward debt
        userRewardDebt[msg.sender] = (totalStakedByUser[msg.sender] * accRewardPerShare) / 1e18;

        uint8 tier = getTier(msg.sender);
        emit TierChanged(msg.sender, tier);
        emit UnstakeRequested(msg.sender, amount, unlockTime);
    }

    function withdraw() external nonReentrant {
        uint256 totalWithdraw = 0;
        UnstakeRequest[] storage requests = unstakeRequests[msg.sender];

        for (uint256 i = 0; i < requests.length; i++) {
            if (requests[i].unlockTime <= block.timestamp && requests[i].amount > 0) {
                totalWithdraw += requests[i].amount;
                requests[i].amount = 0;
            }
        }

        require(totalWithdraw > 0, "Nothing to withdraw");
        safeToken.safeTransfer(msg.sender, totalWithdraw);

        if (totalStakedByUser[msg.sender] == 0) {
            totalStakers--;
        }

        emit Withdrawn(msg.sender, totalWithdraw);
    }

    // =========================================
    // REWARD CLAIMING (USDC real yield)
    // =========================================

    /**
     * @dev Claim accumulated USDC rewards.
     * Rewards are proportional to stake amount and time staked.
     */
    function claimRewards() external nonReentrant {
        uint256 pending = pendingRewards(msg.sender);
        require(pending > 0, "No rewards");

        userRewardDebt[msg.sender] = (totalStakedByUser[msg.sender] * accRewardPerShare) / 1e18;
        userClaimedRewards[msg.sender] += pending;

        rewardToken.safeTransfer(msg.sender, pending);

        emit RewardsClaimed(msg.sender, pending);
    }

    /**
     * @dev View pending USDC rewards for a user.
     */
    function pendingRewards(address user) public view returns (uint256) {
        if (totalStakedByUser[user] == 0) return 0;

        uint256 accumulated = (totalStakedByUser[user] * accRewardPerShare) / 1e18;
        uint256 debt = userRewardDebt[user];

        if (accumulated <= debt) return 0;
        return accumulated - debt;
    }

    function _claimPendingRewards(address user) internal {
        uint256 pending = pendingRewards(user);
        if (pending > 0) {
            userClaimedRewards[user] += pending;
            rewardToken.safeTransfer(user, pending);
            emit RewardsClaimed(user, pending);
        }
    }

    // =========================================
    // TIER (for revenue share & features only, NOT vote power)
    // =========================================
    // Vote power is always 1:1 (1 person = 1 vote) regardless of stake.
    // Staking tiers only affect: revenue share %, feature access, priority queue.

    function getTier(address user) public view returns (uint8) {
        uint256 staked = totalStakedByUser[user];
        if (staked >= DIAMOND_THRESHOLD) return 5;
        if (staked >= PLATINUM_THRESHOLD) return 4;
        if (staked >= GOLD_THRESHOLD) return 3;
        if (staked >= SILVER_THRESHOLD) return 2;
        if (staked >= BRONZE_THRESHOLD) return 1;
        return 0;
    }

    // =========================================
    // VIEW FUNCTIONS
    // =========================================

    function getUserStakes(address user) external view returns (StakeInfo[] memory) {
        return userStakes[user];
    }

    function getUnstakeRequests(address user) external view returns (UnstakeRequest[] memory) {
        return unstakeRequests[user];
    }

    /**
     * @dev Estimated annual USDC yield for a given stake amount.
     * Based on last revenue deposit and current total staked.
     */
    function estimatedAnnualYield(uint256 stakeAmount) external view returns (uint256) {
        if (revenueHistory.length == 0 || totalStaked == 0) return 0;

        // Use last deposit as reference
        RevenueEpoch memory last = revenueHistory[revenueHistory.length - 1];
        // Annualize: assume monthly deposits
        uint256 annualRevenue = last.usdcAmount * 12;
        // User's share
        return (annualRevenue * stakeAmount) / totalStaked;
    }

    /**
     * @dev Full transparency: revenue distribution history
     */
    function getRevenueHistoryCount() external view returns (uint256) {
        return revenueHistory.length;
    }

    /**
     * @dev Get user's complete staking summary
     */
    function getUserSummary(address user) external view returns (
        uint256 stakedAmount,
        uint8 tier,
        uint256 pendingUsdc,
        uint256 totalClaimedUsdc
    ) {
        return (
            totalStakedByUser[user],
            getTier(user),
            pendingRewards(user),
            userClaimedRewards[user]
        );
    }
}

contracts/SAFEToken.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import "@openzeppelin/contracts/token/ERC20/ERC20.sol";
import "@openzeppelin/contracts/token/ERC20/extensions/ERC20Burnable.sol";
import "@openzeppelin/contracts/access/Ownable.sol";

/**
 * @title SAFEToken
 * @dev $SAFE Token for SafeScoring platform
 *
 * Tokenomics (v2 - Sustainable):
 * - Total Supply: 100,000,000 SAFE (100M) - FIXED, no inflation
 * - Decimals: 18
 *
 * Distribution:
 * - 40% Community Rewards (earn via platform usage)
 * - 20% Treasury (development, locked via SAFEVesting)
 * - 20% Team (locked via SAFEVesting: 12-month cliff + 36-month linear)
 * - 10% Initial Liquidity
 * - 10% Revenue Buyback Reserve (bought back with EUR revenue, burned)
 *
 * Key fixes vs v1:
 * - Team/Treasury mint ONLY to vesting contracts (no instant dump)
 * - Buyback burn tracking (EUR revenue → buy $SAFE → burn)
 * - Revenue vs emissions ratio tracked on-chain for transparency
 * - Emissions cap: community rewards decrease over time (halving)
 */
contract SAFEToken is ERC20, ERC20Burnable, Ownable {
    uint256 public constant MAX_SUPPLY = 100_000_000 * 10**18;

    // =========================================
    // ALLOCATION CONSTANTS
    // =========================================

    uint256 public constant COMMUNITY_ALLOCATION = 40_000_000 * 10**18;  // 40%
    uint256 public constant TREASURY_ALLOCATION  = 20_000_000 * 10**18;  // 20% (was 30%)
    uint256 public constant TEAM_ALLOCATION      = 20_000_000 * 10**18;  // 20%
    uint256 public constant LIQUIDITY_ALLOCATION = 10_000_000 * 10**18;  // 10%
    uint256 public constant BUYBACK_ALLOCATION   = 10_000_000 * 10**18;  // 10% NEW

    // =========================================
    // VESTING CONTRACTS (immutable after set)
    // =========================================

    address public teamVestingContract;
    address public treasuryVestingContract;
    bool public vestingContractsLocked; // Once true, cannot change

    // =========================================
    // DISTRIBUTION WALLETS
    // =========================================

    address public communityRewardsWallet;
    address public liquidityWallet;

    // =========================================
    // MINTED TRACKING
    // =========================================

    uint256 public communityMinted;
    uint256 public treasuryMinted;
    uint256 public teamMinted;
    uint256 public liquidityMinted;

    // =========================================
    // BUYBACK & BURN TRACKING (Test 1 fix)
    // =========================================

    uint256 public totalBuybackBurned;       // Total tokens burned via revenue buyback
    uint256 public totalEmitted;             // Total community tokens emitted
    uint256 public totalSpendBurned;         // Tokens burned from user spending (50%)

    // Monthly tracking for revenue/emission ratio
    struct MonthlyStats {
        uint256 emitted;      // Tokens emitted this month
        uint256 burned;       // Tokens burned this month (buyback + spend)
        uint256 timestamp;    // When this month started
    }
    MonthlyStats[] public monthlyStats;
    uint256 public currentMonthIndex;

    // =========================================
    // EMISSION HALVING (deflationary schedule)
    // =========================================

    uint256 public constant INITIAL_MONTHLY_CAP = 500_000 * 10**18; // 500K/month max
    uint256 public constant HALVING_INTERVAL = 365 days;            // Halve yearly
    uint256 public deployTimestamp;
    uint256 public monthlyEmitted; // Current month emissions
    uint256 public lastMonthReset;

    // =========================================
    // RECYCLING
    // =========================================

    uint256 public recycledPool;

    // =========================================
    // EVENTS
    // =========================================

    event TeamTokensMintedToVesting(address indexed vestingContract, uint256 amount);
    event TreasuryTokensMintedToVesting(address indexed vestingContract, uint256 amount);
    event CommunityRewardsMinted(address indexed to, uint256 amount);
    event BuybackBurned(uint256 amount, uint256 totalBuybackBurned);
    event SpendBurned(address indexed user, uint256 spent, uint256 burned);
    event TokensRecycled(address indexed from, uint256 amount);
    event VestingContractsLocked(address team, address treasury);
    event MonthlyStatsRecorded(uint256 month, uint256 emitted, uint256 burned);

    // =========================================
    // CONSTRUCTOR
    // =========================================

    constructor(
        address _communityRewardsWallet,
        address _liquidityWallet
    ) ERC20("SafeScoring Token", "SAFE") Ownable(msg.sender) {
        require(_communityRewardsWallet != address(0), "Invalid community wallet");
        require(_liquidityWallet != address(0), "Invalid liquidity wallet");

        communityRewardsWallet = _communityRewardsWallet;
        liquidityWallet = _liquidityWallet;
        deployTimestamp = block.timestamp;
        lastMonthReset = block.timestamp;

        // Only mint liquidity at deployment - everything else goes through vesting
        _mint(_liquidityWallet, LIQUIDITY_ALLOCATION);
        liquidityMinted = LIQUIDITY_ALLOCATION;

        // Initialize first month stats
        monthlyStats.push(MonthlyStats({
            emitted: 0,
            burned: 0,
            timestamp: block.timestamp
        }));
    }

    // =========================================
    // VESTING SETUP (one-time, then locked)
    // =========================================

    /**
     * @dev Set vesting contracts and lock them permanently.
     * Team and treasury tokens can ONLY be minted to these contracts.
     * This function can only be called ONCE.
     */
    function setAndLockVestingContracts(
        address _teamVesting,
        address _treasuryVesting
    ) external onlyOwner {
        require(!vestingContractsLocked, "Already locked");
        require(_teamVesting != address(0), "Invalid team vesting");
        require(_treasuryVesting != address(0), "Invalid treasury vesting");

        teamVestingContract = _teamVesting;
        treasuryVestingContract = _treasuryVesting;
        vestingContractsLocked = true;

        emit VestingContractsLocked(_teamVesting, _treasuryVesting);
    }

    /**
     * @dev Mint team tokens ONLY to the vesting contract. Not to a wallet.
     */
    function mintToTeamVesting(uint256 amount) external onlyOwner {
        require(vestingContractsLocked, "Vesting not configured");
        require(teamMinted + amount <= TEAM_ALLOCATION, "Exceeds team allocation");

        teamMinted += amount;
        _mint(teamVestingContract, amount);

        emit TeamTokensMintedToVesting(teamVestingContract, amount);
    }

    /**
     * @dev Mint treasury tokens ONLY to the vesting contract.
     */
    function mintToTreasuryVesting(uint256 amount) external onlyOwner {
        require(vestingContractsLocked, "Vesting not configured");
        require(treasuryMinted + amount <= TREASURY_ALLOCATION, "Exceeds treasury allocation");

        treasuryMinted += amount;
        _mint(treasuryVestingContract, amount);

        emit TreasuryTokensMintedToVesting(treasuryVestingContract, amount);
    }

    // =========================================
    // COMMUNITY REWARDS (with emission cap + halving)
    // =========================================

    /**
     * @dev Mint community rewards with monthly emission cap.
     * Cap halves every year to create decreasing inflation.
     */
    function mintCommunityRewards(address to, uint256 amount) external onlyOwner {
        // Reset monthly counter if new month
        if (block.timestamp >= lastMonthReset + 30 days) {
            _recordMonthlyStats();
            monthlyEmitted = 0;
            lastMonthReset = block.timestamp;
        }

        uint256 currentCap = getCurrentMonthlyCap();
        require(monthlyEmitted + amount <= currentCap, "Monthly emission cap reached");

        uint256 remainingAllocation = COMMUNITY_ALLOCATION - communityMinted;

        if (amount <= remainingAllocation) {
            communityMinted += amount;
            _mint(to, amount);
        } else if (remainingAllocation > 0) {
            uint256 fromRecycled = amount - remainingAllocation;
            require(fromRecycled <= recycledPool, "Exceeds available tokens");
            communityMinted += remainingAllocation;
            recycledPool -= fromRecycled;
            _mint(to, amount);
        } else {
            require(amount <= recycledPool, "Exceeds recycled pool");
            recycledPool -= amount;
            _mint(to, amount);
        }

        monthlyEmitted += amount;
        totalEmitted += amount;

        emit CommunityRewardsMinted(to, amount);
    }

    /**
     * @dev Current monthly emission cap (halves yearly).
     * Year 1: 500K/month, Year 2: 250K/month, Year 3: 125K/month, etc.
     */
    function getCurrentMonthlyCap() public view returns (uint256) {
        uint256 yearsSinceDeployment = (block.timestamp - deployTimestamp) / HALVING_INTERVAL;
        uint256 cap = INITIAL_MONTHLY_CAP;
        for (uint256 i = 0; i < yearsSinceDeployment && i < 10; i++) {
            cap = cap / 2;
        }
        // Minimum cap: 10K tokens/month
        if (cap < 10_000 * 10**18) {
            cap = 10_000 * 10**18;
        }
        return cap;
    }

    // =========================================
    // BUYBACK & BURN (Test 1 fix: Revenue > Emissions)
    // =========================================

    /**
     * @dev Burn tokens bought back with platform revenue (EUR→buy SAFE→burn).
     * Called by owner after buying $SAFE from market with subscription revenue.
     * Creates real deflationary pressure linked to business revenue.
     */
    function buybackBurn(uint256 amount) external onlyOwner {
        require(balanceOf(msg.sender) >= amount, "Insufficient balance");
        _burn(msg.sender, amount);
        totalBuybackBurned += amount;

        // Update current month stats
        if (monthlyStats.length > 0) {
            monthlyStats[monthlyStats.length - 1].burned += amount;
        }

        emit BuybackBurned(amount, totalBuybackBurned);
    }

    /**
     * @dev Burn tokens when users spend them (50% burned, 50% recycled).
     * This is the on-chain version of the spend-burn mechanism.
     */
    function spendAndBurn(uint256 amount) external {
        require(balanceOf(msg.sender) >= amount, "Insufficient balance");

        uint256 burnAmount = amount / 2;        // 50% permanently burned
        uint256 recycleAmount = amount - burnAmount; // 50% recycled to reward pool

        _burn(msg.sender, amount);
        recycledPool += recycleAmount;
        totalSpendBurned += burnAmount;

        // Update current month stats
        if (monthlyStats.length > 0) {
            monthlyStats[monthlyStats.length - 1].burned += burnAmount;
        }

        emit SpendBurned(msg.sender, amount, burnAmount);
    }

    // =========================================
    // TRANSPARENCY (on-chain verifiable)
    // =========================================

    /**
     * @dev Is the protocol net-deflationary? (burn > emissions this month)
     */
    function isNetDeflationary() external view returns (
        bool deflationary,
        uint256 currentMonthEmitted,
        uint256 currentMonthBurned,
        int256 netFlow
    ) {
        uint256 emitted = monthlyEmitted;
        uint256 burned = monthlyStats.length > 0
            ? monthlyStats[monthlyStats.length - 1].burned
            : 0;

        int256 flow = int256(burned) - int256(emitted);

        return (flow >= 0, emitted, burned, flow);
    }

    /**
     * @dev Lifetime revenue/emission ratio (basis points).
     * 10000 = break even, >10000 = deflationary, <10000 = inflationary
     */
    function getRevenueEmissionRatioBps() external view returns (uint256) {
        if (totalEmitted == 0) return 10000;
        uint256 totalBurned = totalBuybackBurned + totalSpendBurned;
        return (totalBurned * 10000) / totalEmitted;
    }

    /**
     * @dev Get remaining allocations
     */
    function getRemainingAllocations() external view returns (
        uint256 communityRemaining,
        uint256 treasuryRemaining,
        uint256 teamRemaining,
        uint256 liquidityRemaining,
        uint256 recycledAvailable
    ) {
        return (
            COMMUNITY_ALLOCATION - communityMinted,
            TREASURY_ALLOCATION - treasuryMinted,
            TEAM_ALLOCATION - teamMinted,
            LIQUIDITY_ALLOCATION - liquidityMinted,
            recycledPool
        );
    }

    function getAvailableForRewards() external view returns (uint256) {
        return (COMMUNITY_ALLOCATION - communityMinted) + recycledPool;
    }

    /**
     * @dev Monthly stats history for transparency dashboards
     */
    function getMonthlyStatsCount() external view returns (uint256) {
        return monthlyStats.length;
    }

    // =========================================
    // INTERNAL
    // =========================================

    function _recordMonthlyStats() internal {
        // Start new month
        monthlyStats.push(MonthlyStats({
            emitted: 0,
            burned: 0,
            timestamp: block.timestamp
        }));

        if (monthlyStats.length >= 2) {
            uint256 prevIndex = monthlyStats.length - 2;
            emit MonthlyStatsRecorded(
                prevIndex,
                monthlyStats[prevIndex].emitted,
                monthlyStats[prevIndex].burned
            );
        }
    }
}

